  if (!vertex) {
    console.log({vertex});
    throw new Error("vertex错误 searchAngle");
  }
  
  // 逆时针角度
  maxAngleChild = null;
  minAngleChild = null;
  maxAngle = 0;
  minAngle = 2e308;
  if (vertex2) {
    vector = {
      x: vertex.site.x - vertex2.site.x,
      y: vertex.site.y - vertex2.site.y
    };
  }
