      if (angle < 0) {
        angle += 2 * Math.PI;
      }
      angle2 = angle * 180 / Math.PI;
      /* console.log
             p1: JSON.stringify vertex.site
             p2: JSON.stringify childVertex.site
             angle: angle
             angle2: angle2 */

      // 初始化或比较角度
